func (q *Queries) ListTimeEntriesPaginated(ctx context.Context, arg ListTimeEntriesPaginatedParams) ([]ListTimeEntriesPaginatedRow, error) {
	rows, err := q.db.Query(ctx, listTimeEntriesPaginated,
		arg.EmployeeID,
		arg.Status,
		arg.EmployeeSearch,
		arg.Offset,
		arg.Limit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []ListTimeEntriesPaginatedRow{}
	for rows.Next() {
		var i ListTimeEntriesPaginatedRow
		if err := rows.Scan(
			&i.ID,
			&i.EmployeeID,
			&i.ScheduleID,
			&i.EntryDate,
			&i.StartTime,
			&i.EndTime,
			&i.BreakMinutes,
			&i.HourType,
			&i.ProjectName,
			&i.ProjectNumber,
			&i.ClientName,
			&i.ActivityCategory,
			&i.ActivityDescription,
			&i.Status,
			&i.SubmittedAt,
			&i.ApprovedAt,
			&i.ApprovedByEmployeeID,
			&i.RejectionReason,
			&i.Notes,
			&i.CreatedAt,
			&i.UpdatedAt,
			&i.PaidPeriodID,
			&i.EmployeeFirstName,
			&i.EmployeeLastName,
			&i.ApprovedByFirstName,
			&i.ApprovedByLastName,
			&i.TotalCount,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

