const rejectTimeEntry = `-- name: RejectTimeEntry :one
WITH updated_time_entry AS (
    UPDATE time_entries
    SET
        status = 'rejected'::time_entry_status_enum,
        rejection_reason = $1::text,
        approved_at = NULL,
        approved_by_employee_id = NULL,
        updated_at = NOW()
    WHERE time_entries.id = $2
    RETURNING
        id,
        employee_id,
        schedule_id,
        entry_date,
        start_time,
        end_time,
        break_minutes,
        hour_type,
        project_name,
        project_number,
        client_name,
        activity_category,
        activity_description,
        status,
        submitted_at,
        approved_at,
        approved_by_employee_id,
        rejection_reason,
        notes,
        created_at,
        updated_at,
        paid_period_id
)
SELECT
    te.id,
    te.employee_id,
    te.schedule_id,
    te.entry_date,
    te.start_time,
    te.end_time,
    te.break_minutes,
    te.hour_type,
    te.project_name,
    te.project_number,
    te.client_name,
    te.activity_category,
    te.activity_description,
    te.status,
    te.submitted_at,
    te.approved_at,
    te.approved_by_employee_id,
    te.rejection_reason,
    te.notes,
    te.created_at,
    te.updated_at,
    te.paid_period_id,
    ep.first_name AS employee_first_name,
    ep.last_name AS employee_last_name,
    ap.first_name AS approved_by_first_name,
    ap.last_name AS approved_by_last_name
FROM updated_time_entry te
JOIN employee_profile ep ON ep.id = te.employee_id
LEFT JOIN employee_profile ap ON ap.id = te.approved_by_employee_id
`

